// Helper function to get images for a specific lesson
function getImagesForLesson(lessonId) {
    return Object.entries(EMBEDDED_IMAGES)
        .filter(([key, img]) => img.lesson === lessonId)
        .map(([key, img]) => ({
            id: key,
            url: img.dataUri,
            alt: img.alt,
            caption: img.caption
        }));
}

// Helper function to get a specific image by ID
function getImageById(imageId) {
    const img = EMBEDDED_IMAGES[imageId];
    if (img) {
        return {
            id: imageId,
            url: img.dataUri,
            alt: img.alt,
            caption: img.caption
        };
    }
    return null;
}

// Export for use in modules
if (typeof module !== 'undefined' && module.exports) {
    module.exports = { EMBEDDED_IMAGES, getImagesForLesson, getImageById };
}
